loadUser(id: string) {
  return this.sdk.getUser(id).pipe(
    shareReplay(1),
    catchError((err) => {
      if (err.status === 401) this.router.navigate(['/login']);
      this.toaster.error('Session expired. Please log in again.');
      return of(null);
    }),
  );
}
